module RefModule(
    input wire clk,
    input wire rst_n,
    input wire [3:0] divisor,
    output reg square_wave
);

reg [3:0] obf_counter;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        obf_counter <= 4'd0;
        square_wave <= 1'b0;
    end else begin
        if (obf_counter >= (divisor - 1)) begin
            obf_counter <= 4'd0;
            square_wave <= ~square_wave;
        end else begin
            obf_counter <= obf_counter + 4'd1;
        end
    end
end

endmodule
